// Write a middleware function to validate dynamic route parameters
// Use the req.params object to access the route parameter
// Check if the route parameter is a positive integer
// Call the next function in the middleware chain if valid

buggyStarterCode.javascript:
function validateParam(req, res, next) {
  const param = req.params.id;
  // Check if the parameter is a positive integer
  if (isNaN(param)) {
    return next();
  }
  // Call the next function in the middleware chain
  next();
}

// Use the middleware function to validate the route parameter
app.get('/users/:id', validateParam, (req, res) => {
  // Handle the request
  res.send('Hello World');
});

solutions.javascript:
function validateParam(req, res, next) {
  const param = req.params.id;
  // Check if the parameter is a positive integer
  if (!/^[0-9]+$/.test(param)) {
    return res.status(404).send('Not Found');
  }
  // Call the next function in the middleware chain
  next();
}

// Use the middleware function to validate the route parameter
app.get('/users/:id', validateParam, (req, res) => {
  // Handle the request
  res.send('Hello World');
});
